import requestsimport jsonimport reOLLAMA_URL = "http://localhost:11434/api/generate"JUDGE_PROMPT = """You are an expert software architect evaluating LLM answers.Score the response from 1 to 10 in each category:- correctness (technical accuracy)- completeness (covers requirements)- clarity (structure and readability)- design quality (architecture decisions)Return ONLY valid JSON:{  "correctness": x,  "completeness": x,  "clarity": x,  "design": x,  "overall": x}Do not include explanation."""def extract_json(text):    try:        # remove markdown fences        text = re.sub(r"```json|```", "", text).strip()        # find first JSON object        match = re.search(r"\{.*\}", text, re.DOTALL)        if match:            return json.loads(match.group(0))    except Exception:        pass    return Nonedef judge_answer(judge_model, prompt, answer):    full_prompt = f"""{JUDGE_PROMPT}{prompt}{answer}"""    try:        r = requests.post(            OLLAMA_URL,            json={                "model": judge_model,                "prompt": full_prompt,                "stream": False,                "options": {                    "temperature": 0                }            },            timeout=120        )        if r.status_code != 200:            raise RuntimeError(f"Judge HTTP {r.status_code}")        text = r.json().get("response", "{}")        parsed = extract_json(text)        if parsed:            return parsed        raise ValueError("Invalid JSON from judge")    except Exception as e:        return {            "correctness": 0,            "completeness": 0,            "clarity": 0,            "design": 0,            "overall": 0,            "error": str(e)        }